'use client';

import { ChevronDown } from 'lucide-react';
import { useState } from 'react';

interface AccordionProps {
  title: string;
  children?: React.ReactNode;
}

export default function Accordion({ title, children }: AccordionProps) {
  const [isOpen, setIsOpen] = useState(false);
  return (
    <article className="w-full rounded-md lg:p-4">
      <div
        className="mb-4 flex w-full items-center justify-between border-b border-b-primary cursor-pointer pb-2"
        onClick={() => setIsOpen(!isOpen)}
      >
        <h2 className="flex items-center justify-between">{title}</h2>
        {isOpen ? (
          <ChevronDown
            size={24}
            className="rotate-90 text-gray transition-transform dark:text-white"
          />
        ) : (
          <ChevronDown
            size={24}
            className="rotate-180 text-gray transition-transform dark:text-white"
          />
        )}
      </div>
      {isOpen && <>{children}</>}
    </article>
  );
}
